// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
// WIDGET BASE: FORM
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 2021-05-11 | mmcc | STRY0099400 Remove the icon for going to the split view screen
//                                         Changes made in HTML
// 2.7.0 | 2021-05-18 | raj  | STRY0082332 FIX: Template Designers can create Template Schedules
//                                         Changes in Server Script
// 2.7.0 | 2021-05-21 | mmcc | STRY0099596 Record Watcher on Template Count not Updating
//											emit sends rowCount in params, no need for .Deleted or .Added
//											Change made in Client controller
// 2.7.0 | 2021-05-25 | mmcc | STRY0090508 When Tasker Users click "UI Policies" or "Client Scripts" on the context menu 
// 											they are redirected to a security constraint error
//                                          Changes in HTML and Server Script
// 2.7.0 | 2021-06-23 | mmcc | STRY0079333 Tasker Split View - My Documents and Shared Documents tab error 
// 											In Server Script, formatted file and added missing semicolon
//                                          Changes in CSS and Server Script
// 2.7.0 | 2021-07-25 | raj  | STRY0101803 - changed the split view and needed to remove classification badge form bottom in split view
//																					Changes in HTML only
// 2.7.0 | 2021-07-31 | raj | STRY0079002: FIX: STRETCH- "Paperclip" icon appears in Tasker "Split View", split view page should not show attachment button
//																					Changes in HTML only
// 2.7.0 | 2021-08-09 | mmcc | STRY0104884 Badges do not pass 508/WCAG compliance
// 											In HTML, change CSS selector .assignmentgroup-banner to use .dtech-restricted-group-banner.
// 											In CSS, selector .assignmentgroup-banner removed. Comment added for   
// 											 .dtech-restricted-group-banner to direct to Tasker Theme
//											 then CSS include: Restricted Group Banner CSS Include.
//                                          Changes in HTML and CSS
// 2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
// 											In CSS, selector .taskform-classification-banner declaration removed. Comment added to direct 
// 											 to Tasker Theme then CSS include: Classification Banner CSS Include.
//											 Selector #sp_formfield_status declaration removed, was commented out.
//                                          Changes in CSS
// 2.7.0 | 2021-08-20 | raj  | STRY0108140 -Task Form Preferences - Button Update
//														- This is a technical story to account for the time taken to update the buttons
//                                          Changes in HTML and Client Script
// 2.7.0 | 2021-08-20 | raj  | STRY0105742 -DIA- Organizational Hierarchy Visual Indicators – OU Unit Icon for OUHA
//                                          Changes in HTML
// 2.7.0 | 2021-08-25 | raj  | STRY0107408 -DIA- Org Hierarchy– Request Update Button 
//                                          Added New Button on Data Table at list top
//                                          Changes in Server Script
//                           | no stoyr, but udpated stylying on all buttons to Use OOTB ServiceNow class settings
//                                          Changes in Client Script
// 2.7.0 | 2021-08-26 | raj  | STRY0108170 -DIA- Org Hierarchy– Hierarchy Request Form
//                                          Changes in Server Script and Client Script
// 2.7.0 | 2021-08-21 | raj  | STRY0108599 - Removed the full screen from this widget for Organizational Hierarchy.
// 2.7.0 | 2021-08-30 | raj  | STRY0108629 - bifold settings
// 2.7.0 | 2021-09-07 | mmcc | STRY0105158 - After creation of a new template, redirect is showing the wrong widget on the right column
// 											In Server script, After creating a new Template from the Home page, trap on the page id 
// 											 and table then get the Top Task sys_id and change the the table to route tasks.
//                                          Changes in Server script
// 2.7.0 | 2021-08-30 | raj  | STRY0111049 - Standard Task Form Widget Updater – Placeholder Story
// 2.7.0 | 2021-10-04 | raj  | STRY0105791 - Simple Task Forms- Placeholder Story
//																				Changes in Server and Client Script
// 2.7.0 | 2021-10-8 | mmcc | STRY0109110 - Draft Scheduled Tasks – UI – Delete Modal- Add Descendant tasks count
//											In Service script, Added code to get data.parent_id from rec.getValue('parent')
//											In Client controller, updated watcherChannel subscribe to handle move to parent or redirect
//                                          Changes in Server script and Client controller
//
// 2.7.0 | 2021-10-12 | raj   | STRY0112002 - Task Form Page- Add a "Create Subtask" icon
//																					Changes in Server Script
// 2.7.0 | 2021-08-30 | raj  | STRY0111049 - Standard Task Form Widget Updater – Placeholder Story
//                                         Changes made in HTML, and Client Script
// 2.7.0 | 2021-10-18 | raj  | STRY0109183 - Remove "Tasker Email" related list/ tab when "Disable Email Task Information" is set to true
//                                         Changes made in HTML
// 2.7.0 | 2021-10-18 | raj  | STRY0111888 - HHS- Strong Matrix- Permissive OU Tasking- Visual Indicators
//                                         Changes made in Server and HTML
// 2.7.0 | 2021-10-22 | raj  | DFCT0010583 - Tasker 2.7/DocInt 2.8 Integration - "Sections" added to a "ServiceNow View" for "DocIntegrator Integration" purposes should NOT be displayed on PORTAL
//                                         Changes made in Client Script
// 2.7.0 | 2021-10-22 | mmcc | DFCT0010600 - Deleting the Top Task from Portal App does not redirect to the Tasker Portal Board
//											In Server script, if no rec.parent set data.parent_id = undefined;
//                                          Changes in Server script.
// 2.7.0 | 2021-10-27 | raj | DFCT0010602 - Hovering over the permissive organization lock icon, does not display the right tooltip on "Information" widget
//											In Server script, changed the message
// 2.7.0 | 2021-10-27 | raj | DFCT0010603 - Spelling mistake. HHS-Strong Matrix- Permissive - Org Info Form, hovering over icon a tooltip displays "OU does not allows Useers to be Tasked by other users" 
//														DFCT0010603  - was updated to Remove Icon
//											In Server script, and HTML
// 2.7.0 | 2021-10-29 | mmcc | STRY0110472 - Stretch- 508 Compliant- Delete Buttons- (ALL Red buttons)
//											In HTML, CSS selector .sc-field-error-label is not used; adjusted to use dtech-field-error-label 
//											In CSS, Comment out unused .sc-field-error-label.
//                                          Changes in HTML and CSS
// 2.7.0 | 2021-10-29 | raj | DFCT0010630 - Icons on the new tasks and new templates displays "Record Not found"
//											In HTML
// 2.7.0 | 2021-11-1 | mmcc | DFCT0010601 - Deleting the Top Task logs an error: The Task Tree was not created for Task: . 
//											  Please contact your Tasker administrator to check on the fix script
//											In Server script, added an else to the if(rec.get()) to set data.isValid = data.sys_id == "-1" which handles
//											  redirect from top task delete and new Task, new Template or new OU Member. 
//											  gs.error() uses rec.number so if() now tests for rec.number.length > 0
//											Changes in Server script.
// 2.7.0 | 2021-11-12 | raj  | DFCT0010649 - Tasker Task form spelling error on mouseover icon spelled "Open Assignement". Should be "Open Assignment".
//											Changes in Server script.
// 2.7.0 | 2021-11-14 | raj  | DFCT0010635 - Remove "Context Menu" from all "New" forms in the Tasker system
//											Changes in Client script.
// 2.7.0 | 2021-11-16 | raj  | STRY0113838 - Tasker Settings- Allow for custom "URL Suffix" for Tasker Portal
//                                         Changes made in Client Script
// 2.7.0 | 2021-11-17 | raj  | DFCT0010654 - Spelling Mistake: The "Add a Subtask" plus '+' icon in the Task/Template Information section displays the incorrect tooltip
//                                         Changes made in Server Script
// 2.7.0 | 2021-11-17 | raj  | STRY0114212 - Artifact Story: Task Form- Task Information icons
//                                         Changes made in Server Script, Client Script and HTML
// 2.7.0 | 2021-11-17 | raj  | DFCT0010657 - Create Task is not redirecting after Task Creation
//                                         Changes made in Server Scripot, Client Script, HTML and CSS
// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis added 
//                                         with uib-tooltip control to show full text
//                                         In HTML, added directive dtech-show-ellipsis-with-tooltip in 2 places
//                                         In Server script, for loading data.isModal from input or options added || false;
//                                         added code block to set directive ellipsis params, convert omit_icons to bool and
//                                         set lengthToAddEllipsis longer when header icons are not shown. 
//                                         var params for get widget data-table, added isModal: data.isModal
//                                         Changes made in HTML, CSS and Server script
// 2.7.1 | 2021-12-15 | mmcc | DFCT0010716 - On Tabs (OU, Task) the icons did not align correctly with text 
//                                         at the top of the page
//                                         In HTML, added directive dtech-show-ellipsis-with-tooltip in 2 places
//                                         Added 3 .dtech-align-* selectors and updated .btn-form-menu
//                                         Changes made in HTML and CSS
//
// 2.7.1 | 2021-12-16 | raj | STRY0115311 - DocIntegrator Copy/Move Feature Code Update
//                                         Changes made in Client Controller
// 2.7.1 | 2021-12-16 | raj | DFCT0010477 - Tasker Portal Menu header - "Tasker Email" should be Plural 
//                                         Changes made in Server Script
//------------------------------------------------------------------------------------------------------------------------

// form functionality - URL parameter driven
(function($sp, input, data, options, gs) {
	// DFCT0010657
	var oUserPref = new x_153465_discovert.tasker_User_Form_Preferences();
	if (input && input.getURL==true){
		// if just getting the URL, then get URL and return
		var url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(input.sys_id,input.view);
		data.sys_id = input.sys_id;
		data.pageId = url_Properties.pageId;
		data.pageTable = url_Properties.pageTable;
		data.view = url_Properties.view;
		data.portal_url_ref = url_Properties.portal_url_ref;
		data.isValid = false;
		data.loadingIndicator = true;
		// only call once
		data.getURL = false;
		return;
	}	
	data.loadingIndicator = false;

	/* "use strict"; -linter issues */
	// populate the 'data' variable
	data.attachmentUploadSuccessMsg = gs.getMessage("Attachment upload was successful");
	data.recordAddedMsg = gs.getMessage("Record Added");
	data.updatedMsg = gs.getMessage("updated_uppercase");
	data.exportPDFMsg = gs.getMessage("Export to PDF");
	data.exportPDFLandMsg = gs.getMessage("Export to PDF (landscape)");
	data.addAttachmentMsg = gs.getMessage("Add an attachment");
	data.maxAttachmentSize = parseInt(gs.getProperty("com.glide.attachment.max_size", 1024));
	if (isNaN(data.maxAttachmentSize))
		data.maxAttachmentSize = 24;
	data.largeAttachmentMsg = gs.getMessage("Attached files must be smaller than {0} - please try again", "" + data.maxAttachmentSize + "MB");
	data.attachmentSuccessMsg = gs.getMessage("Attachment successfully uploaded");

	// 2.7.0 | 2021-05-25 | mmcc | STRY0090508 When Tasker Users click "UI Policies" or "Client Scripts" on the context menu 
	//data.isAdmin = gs.hasRole('x_153465_discovert.tasker_user'); //data.isAdmin = gs.hasRightsTo('sp/configure.all/execute', null); //for GLOBAL app
	data.isAdmin = gs.hasRole('admin');
	data.hasRoleTaskerUser = gs.hasRole('x_153465_discovert.tasker_user');

	data.emptyStateTemplate = options.empty_state_template;
	data.disableUIActions = options.disableUIActions === "true";
	data.hideRelatedLists = options.hideRelatedLists || false;
	// STRY0108629
	data.bifold=(input || {}).bifold || (options || {}).bifold || false;
	data.omit_icons=(input || {}).omit_icons || (options || {}).omit_icons || false; 
	data.omitHeaderOptions = (input || {}).omitHeaderOptions || (options || {}).omitHeaderOptions;
	data.omitHeader = (input || {}).omitHeader || (options || {}).omitHeader;

	//------------------------------------------------------------------------------------------------------------------------
	// CUSTOM
	//------------------------------------------------------------------------------------------------------------------------
	// START - RAJ Remove post back on Modals
	// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis added; add || false
	// data.isModal = (input || {}).isModal || (options || {}).isModal;
	data.isModal = (input || {}).isModal || (options || {}).isModal || false;

	// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis
	convertToBool(['omit_icons', 'isModal']);

	// STRY0105791
	data.baseURL = gs.getProperty('glide.servlet.uri');
	if($sp.getPortalRecord()){
		data.service_portal_url_suffix = $sp.getPortalRecord().getValue('url_suffix');
	} else {
		// TODO: May want to pull default from the form load here
		data.service_portal_url_suffix = '';
	}


	data.page_id = $sp.getParameter("id");
	data.sys_id = $sp.getParameter("sys_id");
	data.view = $sp.getParameter("view") || "sp"; // SP default
	data.filter = $sp.getParameter("filter") || $sp.getValue('filter');
	data.isValid = true;
	data.current_user = gs.getUserID();
	if (!options.showFormView) {
		options.showFormView = "false";
	}
	//------------------------------------------------------------------------------------------------------------------------

	if (input) {
		var myUserObject = gs.getUser();
		var currentUser = myUserObject.getDisplayName();

		data.table = input.table;
		data.sys_id = input.sys_id;
		data.view = input.view;

		//STRY0056591
		if (input.parent)
			data.parent = input.parent;
		// STRY0108170 - NOTE: this should pull all values off o a filter 
		// 								to avoid adding all fields being passed like parent above
		if (input.u_ou_parent)
			data.u_ou_parent = input.u_ou_parent;

		//KT REQUEST TYPE
		data.u_request_type = input.u_request_type;

		var result = {};
		if (input._fields) {
			result = $sp.saveRecord(input.table, input.sys_id, input._fields);
			data.sys_id = result.sys_id;
		}

		if (input.sys_id == '-1')
			data.isNewRecord = true;
	} else {
		data.table = options.table || $sp.getParameter("t") || $sp.getParameter("table") || $sp.getParameter("sl_table");
		data.sys_id = options.sys_id || $sp.getParameter("sys_id") || $sp.getParameter("sl_sys_id");
		//STRY0065050
		//data.view = options.view || $sp.getParameter("v") || $sp.getParameter("view") || data.view; // SP default from data.view
	}

	if (input) {
		data.query = $sp.getParameter("query") || options.query || input.query;
	} else {
		data.query = $sp.getParameter("query") || options.query || "";
	}
	data.f = {};
	if (!data.table) {
		return;
	}

	// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis added 
	data.lengthToAddEllipsis = 55;
	data.lengthToAddEllipsisOpt = 63;
	// data.tooltipCustomClass = "dtech-ngPro-tooltip";
	data.tooltipPlacement = "auto bottom";

	if (data.omit_icons == true) {
		data.lengthToAddEllipsis = 150;
	}

	if (data.page_id == 'discovertasker_taskdetails') {
		data.lengthToAddEllipsisOpt = 43;
	} else if (data.page_id == 'discovertasker_relatedtasks') {
		data.lengthToAddEllipsisOpt = 23;
	} else if (data.table == 'x_153465_discovert_discover_routing_template' && data.isModal == true) {
		data.lengthToAddEllipsis = 120;
	}

	// TODO Multi-language
	data.OrgFullscreen16 = {"src":'Fullscreen16.svg', "title": gs.getMessage("Open Organizational Hierarchy in full screen view"), "alt": gs.getMessage('Full Screen View')};
	data.TaskFullscreen16 = {"src":'Fullscreen16.svg', "title": gs.getMessage("Open task in new tab"), "alt": gs.getMessage('Open Task')};	
	if(data.omit_icons!=true){
		data.TreeNodes16 = {"src":'TreeNodes16.svg', "title": gs.getMessage("Open Task Tree View"), "alt": gs.getMessage('Task Tree View')};
		// STRY0114212
		data.DynamicTreeView16 = {"src":'DynamicTreeView16.svg', "title": gs.getMessage("Go to Dynamic Tree View page"), "alt": gs.getMessage('Dynamic Tree View')};
		data.Schedule16 = {"src":'Schedule16.svg', "title": gs.getMessage("Open Duration"), "alt": gs.getMessage('Duration')};
		// DFCT0010649
		data.Member16 = {"src":'Member16.svg', "title": gs.getMessage("Open Assignment"), "alt": gs.getMessage('Assignment')};
		// STRY0112002
		data.Information16 = {"src":'Information16_Black.svg', "title": gs.getMessage("Open Information"), "alt": gs.getMessage('Information')};
		data.Divider = {"src":'Divider_Black.svg', "title": "", "alt": ""};
		// DFCT0010654
		var genericAddTitle = '';
		var genericAddAlt = '';
		switch (data.table){
			case "x_153465_discovert_route_task_instance": case 'x_153465_discovert_route_tasks':
				genericAddTitle = gs.getMessage('Add a SubTask');
				genericAddAlt = gs.getMessage('Create a SubTask');
				break;
			case "x_153465_discovert_discover_office_hierarchy": 
				genericAddTitle = gs.getMessage('Add a Sub OU');
				genericAddAlt = gs.getMessage('Create a Sub OU');
				break;
		}

		data.GenericAdd16 = {"src":'GenericAdd16.svg', "title": genericAddTitle, "alt": genericAddAlt};

		// STRY0111888 - DFCT0010602 - DFCT0010603
		data.LockOpenBadge12 = {"src":'LockOpenBadge12.svg', "title": "Permissive Organizational Unit", "alt": "Organizational Unit is Permissive"};
		data.RestrictedBadge12 = {"src":'RestrictedBadge12.svg', "title": "OU does not allows Useers to be Tasked by other users", "alt": "OU Prevents Permissive Tasking"};			
		// STRY0091260
		data.durationTitle = gs.getMessage('Tasker - Title - Duration Modal');
		data.assignmentTitle = gs.getMessage('Tasker - Title - Assignment Modal');
		data.operationalTitle = gs.getMessage('Tasker - Title - Operational Modal');
		// STRY0109208 - Add Create Icon
		data.createTaskTitle = gs.getMessage('Create Subtask');
	}

	// STRY0113838
	data.url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(data.sys_id,data.view);

	// 2.7.0 | 2021-09-07 | mmcc | STRY0105158 - After creation of a new template, redirect is showing the wrong widget on the right column
	// From new template page, get the Top task for the Template Details Page
	if (data.page_id == 'discovertasker_processtemplatedetails' &&
		data.table == 'x_153465_discovert_discover_routing_template') {
		var grTemp = new GlideRecord('x_153465_discovert_discover_routing_template');
		if (grTemp.get(data.sys_id)) {
			data.sys_id = grTemp.getValue('parent_task_def');
			data.table = 'x_153465_discovert_route_tasks';
		}
	}

	// Form widget is not a supported way to view an attachment
	if (data.table == "sys_attachment") {
		data.tableUnsupported = true;
		return;
	}

	if (gs.tableExists(data.table) == false) //if (!GlideTableDescriptor.isValid(data.table)) //for GLOBAL app
		return;

	if (!data.sys_id)
		return;

	//Possible Disabled for Restricted Tasks
	var rec = new GlideRecord(data.table);

	//var rec = new GlideRecordSecure(data.table); //var rec = $sp.getRecord(data.table, data.sys_id);  //for GLOBAL app
	//STRY0071033: 4. GlideRecord's get() function should be enclosed in an if() statement
	// 2.7.0 | 2021-11-1 | mmcc | DFCT0010601 - Deleting the Top Task logs an error: The Task Tree was not created for Task
	// rec.get(-1) = true
	if (rec.get(data.sys_id)) {
		data.isValid = rec.isValid() || data.sys_id == "-1";
	} else {
		data.isValid = data.sys_id == "-1";
	}

	if (!data.isValid)
		return;

	// 2.7.0 | 2021-10-22 | mmcc | DFCT0010600 - Deleting the Top Task from Portal App does not redirect to the Tasker Portal Board
	// DFCT0010600 old if statement
	//if (!data.parent_id && rec.parent) {
	//	data.parent_id = rec.getValue('parent');
	//}
	// DFCT0010600 new if statement
	if (rec.parent) {
		data.parent_id = rec.getValue('parent');
	} else {
		data.parent_id = undefined;
	}

	// STRY0097476
	data.emailEnabled = (data.table == "x_153465_discovert_route_task_instance" && new uiConditionCheck().displaySendTaskAsEmailUIAction(rec));

	// STRY0063746 - this function takes different glide record types and returns the documents, attachments and shared values for that object
	var tDS = new taskerDocumentScripts();
	var currentAttachDocSettings = tDS.getAttachmentAndDocumentSettings(rec);

	//------------------------------------------------------------------------------------------------------------------------
	// CUSTOM: DOC. INT INTEGRATION - INITIALIZING VARIABLES 
	//------------------------------------------------------------------------------------------------------------------------
	//STRY0063746 - this function takes different glide record types and returns the documents, attachments and shared values for that object
	data.SNAttachmentsON = currentAttachDocSettings.sNOWAttachmentsOn;
	data.DocIntON = currentAttachDocSettings.docIntDocumentsOn;
	//STRY0059178 | Shared Documents Folder
	data.DocIntShareFolderON = currentAttachDocSettings.sharingDocuments;
	data.AttachmentSharedFolderON = currentAttachDocSettings.sharingAttachments;

	data.table = rec.getRecordClassName();
	//data.tableHierarchy = GlideDBObjectManager.getTables(data.table).toArray().join(); //for GLOBAL app
	var table = new GlideTableHierarchy(data.table);
	data.tableHierarchy = table.getTables();
	data.canWrite = rec.canWrite();
	// STRY0050440
	data.canCreate = rec.canCreate();
	var hasRecordAccess = data.sys_id == "-1" ? rec.canCreate() : data.canWrite;

	//STRY0014160: If user doesn't have Read access, stop here.
	data.hasRecordReadAccess = true;
	if (data.table == "x_153465_discovert_route_task_instance") {
		data.hasRecordReadAccess = rec.canRead();
		if (!data.hasRecordReadAccess) {
			// STRY0105791
			var link = '<a href="../' + data.service_portal_url_suffix + '">Tasker Portal</a>';
			var message = 'You do not have permission to view this Task. ' + link + ' .<br/>';
			gs.addErrorMessage(message);
			return;
		}
	}

	// STRY0111888
	data.permissiveOUTasking = false;
	if (data.table == "x_153465_discovert_discover_office_hierarchy") {
		data.permissiveOUTasking = gs.getProperty('x_153465_discovert.PermissiveOUTaskingOptions') != 'Off'; 
		data.taskingUnlocked = rec.u_ou_is_permissive == true;
	}

	//data.canAttach = data.canWrite && gs.hasRole(gs.getProperty('glide.attachment.role')) && !GlideTableDescriptor.get(data.table).getED().getBooleanAttribute("no_attachment"); //for GLOBAL app
	//var gtd = new GlideTableDescriptor(data.table);
	//&& !gtd.get(data.table).getED().getBooleanAttribute("no_attachment"); 
	data.f = $sp.getForm(data.table, data.sys_id, data.query, data.view);

	// STRY0063505 | in debugging the process docs story, we realized data.isActive was only set if the field was on the form.
	data.isActive = false;
	if (data.f._fields.active) {
		data.isActive = data.f._fields.active.value;
	} else {
		// STRY0063505 |	NOTE: if the active field exists, use it.  If not, look for u_active, if neither, accept the default setting of false
		if (rec.isValidField('active')) {
			data.isActive = rec.active;
		} else if (rec.isValidField('u_active')) {
			data.isActive = rec.u_active;
		} // otherwise will default to false setting above.
	}

	data.canAttach = data.canWrite && gs.hasRole(gs.getProperty('glide.attachment.role')); //&& (data.isActive == 'true')


	//------------------------------------------------------------------------------------------------------------------------
	// BEGING CUSTON
	//------------------------------------------------------------------------------------------------------------------------

	//------------------------------------------------------------------------------------------------------------------------
	// 1. CUSTOM: CLASSIFICATION BAR
	//------------------------------------------------------------------------------------------------------------------------
	// STRY0063505 | Include Attachments since we dropped attachment properties
	// The fitler needs the "sys_id" of the object for attachments and Shared Attachments
	// get those sys_ids based on the table, then use it to set the filter
	// Needed this additional If statement b/c Task instances users task tree object
	// Process Template is just that rec sys_id
	// Process Task Template is the Process Template sys_id as the filter
	var myAttachSys_ID = data.sys_id; // set to the defualt
	data.sharedAttachSys_ID = data.sys_id + ''; // set to the defualt
	data.sharedAttachTableName = '';

	if (data.table == "x_153465_discovert_route_task_instance") {
		data.sharedAttachSys_ID = rec.u_task_tree.sys_id + '';
		data.sharedAttachTableName = 'x_153465_discovert_task_tree';
	}
	if (data.table == "x_153465_discovert_discover_routing_template") {
		data.sharedAttachSys_ID = data.sys_id + '';
		data.sharedAttachTableName = 'x_153465_discovert_discover_routing_template';
	}
	if (data.table == "x_153465_discovert_route_tasks") {
		// STRY0063505 | This table points at the Process Template Table instead of the Process Template Task table for the shared attachments
		data.sharedAttachSys_ID = rec.tasker_process_definition.sys_id + '';
		data.sharedAttachTableName = 'x_153465_discovert_discover_routing_template';
	}

	if (data.table == "x_153465_discovert_war_sar_reporting" && data.sys_id != -1) {
		if (data.f._fields.classification) data.f.classification = data.f._fields.classification.displayValue;
	}

	//In preparation to go-live with Delivery Customization: 04.18.20
	if (data.table == "x_153465_discovert_route_task_instance" && data.sys_id != -1) {
		if (data.f._fields.number) data.number = data.f._fields.number.displayValue;
		// STRY0051139
		data.task_name = rec.task_name; //data.number + ": " + data.f._fields['short_description']["displayValue"];
		data.f.task_instance__state = '';
		if (data.f._fields.classification) data.f.classification = data.f._fields.classification.displayValue;
		if (data.f._fields.assignment_group) data.f.assignment_group = data.f._fields.assignment_group.displayValue;

		// 2.7.0 | 2021-11-1 | mmcc | DFCT0010601 - Deleting the Top Task logs an error: The Task Tree was not created for Task
		if (!rec.u_task_tree && rec.number.length > 0) {
			gs.error('The Task Tree was not created for Task: ' + rec.number + '.  Please contact your Tasker administrator to check on the fix script.');
		}
		setBreadcrumbs(data.page_id, data.task_name);
	}

	if (data.table == "x_153465_discovert_discover_routing_template" & data.sys_id != -1) {
		if (data.f._fields.template_name) data.f.template_name = data.f._fields.template_name.displayValue;
	}

	//------------------------------------------------------------------------------------------------------------------------
	// 2. CUSTOM: TABS
	//------------------------------------------------------------------------------------------------------------------------
	for (var i in data.f._related_lists) {
		var rl = data.f._related_lists[i];

		// STRY0059424 | Include Attachments since we dropped attachment properties
		if ((rl.table == "sys_attachment") && (rl.label == "Shared Attachments")) {
			if ((data.AttachmentSharedFolderON == false) || (data.SNAttachmentsON == false)) {
				// shared attachments or SNOW attachments are off, skip adding
				continue;
			}
		}
		if ((rl.table == "sys_attachment") && (rl.label == "Attachments")) {
			if (data.SNAttachmentsON == false) {
				// shared attachments or SNOW attachments are off, skip adding
				continue;
			} else if (data.table == "x_153465_discovert_discover_routing_template" && data.AttachmentSharedFolderON == false) {
				// STRY0063505 The Process Template is using "Attachments" as the "Shared Attachments" for the process Tree
				// NOTE: TODO - if we are able to change the label on the native pages, then we would not need this statement here.
				// The backend will be show "Attachments" until we can figure it out 
				continue;
			}
		}


		//------------------------------------------------------------------------------------------------------------------------
		// 2.1. CUSTOM: RELATED LIST DETAIL OPEN MODE: MODAL OR REDIRECT?
		//------------------------------------------------------------------------------------------------------------------------

		var open_row_details_in_modal = false;

		if (data.page_id == "discovertasker_taskdetails" && data.table == "x_153465_discovert_route_task_instance" && rl.table == "x_153465_discovert_tasker_requests") open_row_details_in_modal = true;
		if (rl.table == "x_153465_discovert_tasker_email") open_row_details_in_modal = true;
		if (data.page_id == "discovertasker_processtemplatedetails" && data.table == "x_153465_discovert_route_tasks") open_row_details_in_modal = true;
		if (data.page_id == "discovertasker_detailsdrilldown" && data.table == "x_153465_discovert_route_task_instance") open_row_details_in_modal = true;
		if (data.page_id == "discovertasker_officehierarchy" && data.table == "x_153465_discovert_discover_office_hierarchy" && rl.table == "x_153465_discovert_route_task_instance") open_row_details_in_modal = true;
		if (data.page_id == undefined && data.table == "x_153465_discovert_route_task_instance" && rl.table == "x_153465_discovert_route_task_instance") open_row_details_in_modal = true;
		if (data.table == "x_153465_discovert_discover_routing_template") open_row_details_in_modal = true;
		if (rl.table == "x_153465_discovert_discover_office_members") open_row_details_in_modal = true;
		// STRY0108170
		if (rl.table == "x_153465_discovert_tasker_requests") open_row_details_in_modal = true;

		if (data.page_id == "discovertasker_customtasker_details" && data.table == "x_153465_discovert_war_sar_reporting") open_row_details_in_modal = true;
		// STRY0074663
		if (rl.table == "x_153465_discovert_organizational_contacts") open_row_details_in_modal = true;

		//------------------------------------------------------------------------------------------------------------------------
		// 2.2. CUSTOM: RELATED LIST SORT AND DIRECTION
		//------------------------------------------------------------------------------------------------------------------------

		var o = "";
		var d = "";

		//2.5.13 | KT | REQ | STRY0073625
		if (rl.table == "x_153465_discovert_tasker_requests") {
			o = "number";
			d = "desc";
		}

		if (rl.table == "x_153465_discovert_tasker_schedule") {
			o = "next_run_date";
			d = "asc";
		}

		if (rl.table == "x_153465_discovert_discover_office_members") {
			o = "office_member";
			d = "asc";
		}

		// STRY0074663
		if (rl.table == "x_153465_discovert_organizational_contacts") {
			o = "u_user_information";
			d = "asc";
		}

		if (rl.table == "x_153465_discovert_route_task_instance") {
			o = "task_order";
			d = "asc";
		}

		// STRY0092475
		var rlView = data.view;
		// DFCT0010477
		rl.title = getTabTitle(rl.table, rl.label);
		// STRY0092475 - this is a special case as we want to order the list to put the newest ask at the top instead of listing them by task order
		if (rl.table == "x_153465_discovert_route_task_instance" && data.table == "x_153465_discovert_discover_routing_template") {
			// STRY0097809
			rlView = "sp";
			rl.title = rl.label;
			o = "number";
			d = "desc";
			// STRY0092475 - related list uses a relationshiop and for some reason the rl.field value is undefined for relationships
			rl.field = 'u_parent_template';
		}

		//------------------------------------------------------------------------------------------------------------------------
		// 2.4. CUSTOM: RELATED LIST FILTER
		//------------------------------------------------------------------------------------------------------------------------
		var filter = rl.field + "=" + data.sys_id;
		// STRY0059424 | Include Attachments since we dropped attachment properties
		if ((rl.table == "sys_attachment") && (rl.label == "Shared Attachments") && (data.AttachmentSharedFolderON == true)) {
			// STRY0063505 |	Modified to set this above based on table
			filter = 'table_sys_id' + "=" + data.sharedAttachSys_ID;
		} else {
			if ((rl.table == "sys_attachment") && (rl.label == "Attachments")) {
				// STRY0063505 |	Modified to set this above based on table
				filter = 'table_sys_id' + "=" + myAttachSys_ID;
			}
		}
		// STRY0093948 - when a row is added or removed, trap the event from Tasker Data Table and update related list count	
		rl.filter = filter;

		// STRY0059145 | The previous implementation was using just rl.table for the target inthe HTML for loading data and counts.
		// Any time the same table is added 2 times in the HTML, the target will be the same for both tables.  
		// a new field was created, rl.targetId, by concatenating rl.table with rl.label(without spaces).
		// this new field will be used instead of rl.table in the target fields of the HTML
		rl.targetId = rl.table + rl.label.replace(/ /g, "_");

		// STRY0046028 - determine if user can create for the related list
		var userInfoScript = new UserInfoScripts();
		switch (rl.table) {
			case "x_153465_discovert_discover_office_members":
				rl.canCreate = userInfoScript.userCanCreateMem(data.sys_id);
				break;
			case "x_153465_discovert_discover_office_hierarchy":
				rl.canCreate = userInfoScript.userCanCreateOU(data.sys_id);
				break;
			case "x_153465_discovert_route_tasks":
				rl.canCreate = userInfoScript.userHasProcessRights(rec);
				break;
			case "x_153465_discovert_discover_routing_template":
				rl.canCreate = userInfoScript.userHasProcessRights(rec);
				break;
			case "x_153465_discovert_tasker_schedule":
				// STRY0082332 - FIX: Template Designers can create Template Schedules
				rl.canCreate = new uiConditionCheck().runTemplateUIAction(rec);
				break;
			case "x_153465_discovert_organizational_contacts":
				rl.canCreate = true;
				break;
			case "x_153465_discovert_route_task_instance":
				// STRY0076291
				//rl.canCreate = (((rec.u_task_requester == data.current_user) || (rec.assigned_to == data.current_user)) && rec.active == true);
				// DFCT0010482 
				data.canCreateSubTask = new uiConditionCheck().canCreateSubTask(rec);
				rl.canCreate = data.canCreateSubTask;

				break;

			default:
				rl.canCreate = false;

		}
		//------------------------------------------------------------------------------------------------------------------------
		// 2.5. CUSTOM: WIDGET PARAMETERS
		//------------------------------------------------------------------------------------------------------------------------
		// NOTE: moved below the setting of canCreate so that can be used in the show_new
		var params = {
			o: o,
			d: d,
			table: rl.table,
			filter: filter,
			// STRY0107408
			show_new: rl.canCreate,
			open_new_in_modal: true,
			//STRY0092475: 04/01/2020
			view: rlView,
			title: rl.title,
			// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis added 
			isModal: data.isModal,
			open_row_details_in_modal: open_row_details_in_modal
			//show_breadcrumbs: true
		};

		//------------------------------------------------------------------------------------------------------------------------
		// 2.5. CUSTOM: RELATED LIST CALL WIDGET 
		//------------------------------------------------------------------------------------------------------------------------
		rl.widget = $sp.getWidget('discovertasker-widget-data-table', params);

	}

	// STRY0061245 - while looking at adding attachments, this code was repeated in the for loop each time
	if (options.page) {
		var page = new GlideRecord('sp_page');
		if (page.get(options.page))
			data.page = page.getDisplayValue('id');
	}
	if (!data.page) {
		data.page = "form";
	}

	//------------------------------------------------------------------------------------------------------------------------
	// CUSTOM: ATTACHMENTS AND SHARED ATTACHMENTS
	//------------------------------------------------------------------------------------------------------------------------
	// STRY0059424 | Include Attachments since we dropped attachment properties
	// STRY0061245 | Include Attachments since we dropped attachment properties
	// STRY0063505 | The data.task_sysid field was used only below.  
	data.sharedAttachmentWidgetCount = 0;
	data.myAttachmentWidgetCount = 0;
	// DFCT0010343 - TUP - moved creation of attachments to client script


	//------------------------------------------------------------------------------------------------------------------------
	// 3. CUSTOM: N TAB: PROGRESS BAR & AUDIT WIDGET 
	//------------------------------------------------------------------------------------------------------------------------
	data.widgetInstanceMultipleBar = $sp.getWidget('discovertasker-statesmultiplebar', {
		table: data.table,
		sys_id: data.sys_id
	});

	data.widgetInstanceAuditNotes = $sp.getWidget('widget-ticket-conversation', {
		table: data.table,
		sys_id: data.sys_id,
		includeExtended: true,
		title: "${Activity}",
		use_dynamic_placeholder: true,
		btnLabel: "${Post}"
	});

	//------------------------------------------------------------------------------------------------------------------------
	// 4. DOC. INT INTEGRATION
	//------------------------------------------------------------------------------------------------------------------------
	//STRY0042042: DI Integration: Turn on/off DocInt Attachments and SNOW OOB Attachments
	//STRY0046049: DI Integration: Enable/Disable upload document feature to SharePoint
	// STRY0086644 - added check for DocId not provided	
	if (data.DocIntON && (data.sys_id != -1 && data.sys_id != '') &&
		(data.table == 'x_153465_discovert_route_task_instance' ||
		 data.table == 'x_153465_discovert_discover_routing_template' ||
		 data.table == 'x_153465_discovert_route_tasks')) {

		// STRY0063505 | Added a check for both boolean and string value of true
		if (data.isActive == "true" || data.isActive == true) data.isActive = true;
		else data.isActive = false;
		// STRY0111049
		data._docint_widget = new x_dtll2_contentint.SFWHelper().getWidgetFormConfigurationTabs(data.table, data.view, data.sys_id);
	}


	//------------------------------------------------------------------------------------------------------------------------
	// 5. CUSTOM: GET TABTITLE
	//------------------------------------------------------------------------------------------------------------------------
	function getTabTitle(table_name, related_table_name) {
		var tabTitle = '';
		// TODO - Multi language
		switch (table_name) {
			case "x_153465_discovert_route_task_instance":
				tabTitle = 'Subtasks';
				break;
			case "x_153465_discovert_route_tasks":
				tabTitle = 'Subtasks';
				break;
			case "x_153465_discovert_discover_office_hierarchy":
				tabTitle = 'Sub OUs';
				break;
			case "x_153465_discovert_discover_office_members":
				tabTitle = 'OU Members';
				break;
			case "x_153465_discovert_discover_routing_template":
				tabTitle = 'Template Instances';
				break;
				// STRY0074663
			case "x_153465_discovert_organizational_contacts":
				tabTitle = 'Contacts';
				break;
			// DFCT0010477
			case "x_153465_discovert_tasker_email":
				tabTitle = 'Tasker Emails';
				break;
			default:
				tabTitle = related_table_name;

		}
		return tabTitle;
	}

	//------------------------------------------------------------------------------------------------------------------------
	// 6. CUSTOM: SET BREADCRUMNS
	//------------------------------------------------------------------------------------------------------------------------
	function setBreadcrumbs(page_id, task_name) {
		var title = ""; //"Task Details: ";
		if (page_id == "discovertasker_taskdetails") {
			data.breadcrumbs = [{
				label: title + task_name,
				url: "#"
			} //parent
							   ]; //this
		}

		if (page_id == "discovertasker_relatedtasks") {
			data.breadcrumbs = [{
				label: title + task_name,
				url: "?id=discovertasker_taskdetails&table=" + data.table + "&sys_id=" + data.sys_id
			}, //parent
								{
									label: "Related Tasks",
									url: '#'
								}
							   ]; //this
		}
		if (page_id == "discovertasker_newtask") {
			data.breadcrumbs = [{
				label: "New Item",
				url: '#'
			}]; //this
		}

	}
	//----------------------------------test prompt for instance notation


	if (input) {
		if (input.processInstanceName != undefined) {
			data.processInstanceName = input.processInstanceName;
			data.test = new RunProcessTemplate().runProcessTemplate(data.sys_id, data.processInstanceName);
		}
	}


	//------------------------------------------------------------------------------------------------------------------------
	// END CUSTON
	//------------------------------------------------------------------------------------------------------------------------

	// Activity formatter is hardcoded to set specific options
	for (var f in data.f._formatters) {
		var fm = data.f._formatters[f];
		if (fm.formatter == "activity.xml") {
			fm.hardcoded = true;
			fm.widgetInstance = $sp.getWidget('widget-ticket-conversation', {
				table: data.table,
				sys_id: data.sys_id,
				includeExtended: true,
				title: 'Audit/Notes', //"${Activity}",
				use_dynamic_placeholder: true,
				btnLabel: "${Post}"
			});
		} else if (fm.formatter == "com_glideapp_servicecatalog_veditor" || fm.formatter == "com_glideapp_questionset_default_question_editor") {
			var qsConfig = $sp.getValue('quick_start_config');
			if (qsConfig)
				qsConfig = JSON.parse(qsConfig)[0];
			fm.widgetInstance = $sp.getWidget(fm.widget, {
				table: data.table,
				sys_id: data.sys_id,
				readonly_variable_editor: qsConfig ? qsConfig.readonly_variable_editor : 'false'
			});
		} else
			fm.widgetInstance = $sp.getWidget(fm.widget, data);
	}

	// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis
	function convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}

})($sp, input, data, options, gs);
